        // Strip "wx" / "ELJ" / "kwx" prefix from a class name.
        std::string PerlStripPrefix(const std::string& name)
        {
            if (name.size() > 2 && name[0] == 'w' && name[1] == 'x')
                return name.substr(2);
            if (name.size() > 3 && name[0] == 'E' && name[1] == 'L' && name[2] == 'J')
                return name.substr(3);
            if (name.size() > 3 && name[0] == 'k' && name[1] == 'w' && name[2] == 'x')
                return name.substr(3);
            return name;
        }

        // "wxButton" -> "Button.pm"
        std::string PerlPMFileName(const std::string& class_name)
        {
            return PerlStripPrefix(class_name) + ".pm";
        }

        // "wxButton" -> "wx::FFI::Raw::Button"
        std::string PerlRawPackageName(const std::string& class_name)
        {
            return "wx::FFI::Raw::" + PerlStripPrefix(class_name);
        }

        // "wxButton" -> "wx::Button"
        std::string PerlOOPackageName(const std::string& class_name)
        {
            return "wx::" + PerlStripPrefix(class_name);
        }

        bool IsVoidReturn(const std::string& return_type)
        {
            return return_type.empty() || return_type == "void";
        }

        bool IsStringReturn(const FunctionDecl& func)
        {
            if (func.return_type == "TString" || func.return_type == "TStringOut")
                return true;
            if (func.return_macro == "TClass" && func.return_arg == "wxString")
                return true;
            return false;
        }

        bool IsBoolReturn(const FunctionDecl& func)
        {
            return func.return_type == "TBool" || func.return_type == "TBoolInt";
        }

        // True if function returns a class pointer (not wxString).
        bool IsClassReturn(const FunctionDecl& func)
        {
            return (func.return_macro == "TClass" || func.return_macro == "TSelf" ||
                    func.return_macro == "TClassRef") &&
                   func.return_arg != "wxString" && !func.return_arg.empty();
        }

        // True if first param is TClass(ClassName) matching the function's own class (pseudo-self).
        bool HasPseudoSelf(const FunctionDecl& func)
        {
            if (func.has_self || func.class_name.empty() || func.params.empty())
                return false;
            const auto& first = func.params[0];
            return first.macro_name == "TClass" && first.macro_arg == func.class_name;
        }

        // Find the nearest parent class that has methods (is actually wrapped).
        std::string FindWrappedParent(const std::string& class_name, const ParsedFFI& ffi,
                                      const std::unordered_set<std::string>& wrapped_classes)
        {
            auto iter = ffi.parent_map.find(class_name);
            std::set<std::string> visited;
            while (iter != ffi.parent_map.end())
            {
                const auto& parent = iter->second;
                if (visited.count(parent))
                    break;
                visited.insert(parent);
                if (wrapped_classes.count(parent))
                    return parent;
                iter = ffi.parent_map.find(parent);
            }
            return "";
        }

