        // Map constructor method_name to Perl sub name.
        std::string PerlCtorName(const FunctionDecl& func)
        {
            if (func.method_name == "Create")
                return "new";
            // "CreateEmpty" -> "new_empty"
            std::string suffix = func.method_name.substr(6);  // strip "Create"
            if (suffix.empty())
                return "new";
            return "new_" + ToSnakeCase(suffix);
        }

        // Count valid functions in a class (for diagnostics and skipping empty classes).
        size_t CountValidFunctions(const ClassInfo& cls)
        {
            size_t count = 0;
            for (const auto& f: cls.methods)
            {
                if (IsValidFunction(f))
                    ++count;
            }
            return count;
        }

        // Check if any method in a class uses wxString (input or output).
        bool ClassNeedsString(const ClassInfo& cls)
        {
            for (const auto& f: cls.methods)
            {
                if (!IsValidFunction(f))
                    continue;
                if (IsStringReturn(f))
                    return true;
                for (const auto& p: f.params)
                {
                    if (p.macro_name == "TClass" && p.macro_arg == "wxString")
                        return true;
                }
            }
            return false;
        }

